  // Reporting Handlers
  const handleOpenReport = (item: Equipment) => {
    if (reportingEqId === item.id) {
        setReportingEqId(null);
    } else {
        setReportingEqId(item.id);
        setReportDescription(item.anomaly || "");
        setReportTags(item.anomalyTags || []);
        setReportQuantity(1);
        setExpandedDocId(null);
